def _get_root_and_type_from_text(
    text: str, *, input_type: Optional[str], **lxml_kwargs: Any
) -> Tuple[Any, str]:
    if input_type == "text":
        return text, input_type
    try:
        data = json.loads(text)
    except ValueError:
        data = _NOT_SET
    if data is not _NOT_SET:
        return data, "json"
    if input_type == "json":
